examples.example:
{
  "id": "role-agent",
  "name": "Insurance Agent",
  "type": "human",
  "description": "Collects application data and submits to system"
}

example.generated_config:
{
  "process": {
    "id": "proc-insurance-001",
    "name": "Simple Application Process",
    "description": "Linear application review process",
    "version": "1.0.0"
  },
  "metadata": {
    "context": "Insurance",
    "complexity": "simple",
    "estimatedDuration": "1 week"
  },
  "roles": [
    {
      "id": "role-agent",
      "name": "Insurance Agent",
      "type": "human",
      "description": "Submits applications"
    },
    {
      "id": "role-system",
      "name": "System",
      "type": "system",
      "description": "Validates and routes"
    },
    {
      "id": "role-underwriter",
      "name": "Underwriter",
      "type": "human",
      "description": "Reviews and decides"
    }
  ],
  "milestones": [
    {
      "id": "ms-submitted",
      "name": "Application Submitted",
      "description": "Initial submission complete"
    },
    {
      "id": "ms-reviewed",
      "name": "Review Complete",
      "description": "Underwriting decision made"
    }
  ],
  "elements": [
    {
      "id": "elem-start-1",
      "type": "startEvent",
      "name": "Application Received",
      "outgoing": ["flow-1"]
    },
    {
      "id": "elem-task-1",
      "type": "userTask",
      "name": "Submit Application",
      "assignee": "role-agent",
      "incoming": ["flow-1"],
      "outgoing": ["flow-2"]
    },
    {
      "id": "elem-task-2",
      "type": "serviceTask",
      "name": "Validate Data",
      "assignee": "role-system",
      "incoming": ["flow-2"],
      "outgoing": ["flow-3"]
    },
    {
      "id": "elem-task-3",
      "type": "userTask",
      "name": "Review Application",
      "assignee": "role-underwriter",
      "incoming": ["flow-3"],
      "outgoing": ["flow-4"]
    },
    {
      "id": "elem-end-1",
      "type": "endEvent",
      "name": "Process Complete",
      "incoming": ["flow-4"]
    }
  ],
  "flows": [
    {
      "id": "flow-1",
      "sourceRef": "elem-start-1",
      "targetRef": "elem-task-1"
    },
    {
      "id": "flow-2",
      "sourceRef": "elem-task-1",
      "targetRef": "elem-task-2"
    },
    {
      "id": "flow-3",
      "sourceRef": "elem-task-2",
      "targetRef": "elem-task-3"
    },
    {
      "id": "flow-4",
      "sourceRef": "elem-task-3",
      "targetRef": "elem-end-1"
    }
  ],
  "lanes": [
    {
      "id": "lane-role-agent",
      "name": "Insurance Agent",
      "flowNodeRefs": ["elem-task-1"]
    },
    {
      "id": "lane-role-system",
      "name": "System",
      "flowNodeRefs": ["elem-task-2"]
    },
    {
      "id": "lane-role-underwriter",
      "name": "Underwriter",
      "flowNodeRefs": ["elem-task-3"]
    }
  ]
}

{
  "process": {
    "id": "proc-insurance-002",
    "name": "Approval Process with Decisions",
    "description": "Application process with validation and approval decisions",
    "version": "1.0.0"
  },
  "elements": [
    {
      "id": "elem-start-1",
      "type": "startEvent",
      "name": "Start",
      "outgoing": ["flow-1"]
    },
    {
      "id": "elem-task-1",
      "type": "serviceTask",
      "name": "Validate Application",
      "assignee": "role-system",
      "incoming": ["flow-1"],
      "outgoing": ["flow-2"]
    },
    {
      "id": "elem-gateway-1",
      "type": "exclusiveGateway",
      "name": "Complete?",
      "incoming": ["flow-2"],
      "outgoing": ["flow-3", "flow-4"]
    },
    {
      "id": "elem-task-2",
      "type": "userTask",
      "name": "Fix Application",
      "assignee": "role-agent",
      "incoming": ["flow-4"],
      "outgoing": ["flow-5"]
    },
    {
      "id": "elem-task-3",
      "type": "userTask",
      "name": "Review Application",
      "assignee": "role-underwriter",
      "incoming": ["flow-3", "flow-5"],
      "outgoing": ["flow-6"]
    },
    {
      "id": "elem-gateway-2",
      "type": "exclusiveGateway",
      "name": "Decision",
      "incoming": ["flow-6"],
      "outgoing": ["flow-7", "flow-8"]
    },
    {
      "id": "elem-end-1",
      "type": "endEvent",
      "name": "Approved",
      "incoming": ["flow-7"]
    },
    {
      "id": "elem-end-2",
      "type": "endEvent",
      "name": "Declined",
      "incoming": ["flow-8"]
    }
  ],
  "flows": [
    {
      "id": "flow-1",
      "sourceRef": "elem-start-1",
      "targetRef": "elem-task-1"
    },
    {
      "id": "flow-2",
      "sourceRef": "elem-task-1",
      "targetRef": "elem-gateway-1"
    },
    {
      "id": "flow-3",
      "name": "Complete",
      "sourceRef": "elem-gateway-1",
      "targetRef": "elem-task-3",
      "conditionExpression": "${application.isComplete == true}"
    },
    {
      "id": "flow-4",
      "name": "Incomplete",
      "sourceRef": "elem-gateway-1",
      "targetRef": "elem-task-2",
      "conditionExpression": "${application.isComplete == false}"
    },
    {
      "id": "flow-5",
      "sourceRef": "elem-task-2",
      "targetRef": "elem-task-3"
    },
    {
      "id": "flow-6",
      "sourceRef": "elem-task-3",
      "targetRef": "elem-gateway-2"
    },
    {
      "id": "flow-7",
      "name": "Approve",
      "sourceRef": "elem-gateway-2",
      "targetRef": "elem-end-1",
      "conditionExpression": "${decision == 'APPROVED'}"
    },
    {
      "id": "flow-8",
      "name": "Decline",
      "sourceRef": "elem-gateway-2",
      "targetRef": "elem-end-2",
      "conditionExpression": "${decision == 'DECLINED'}"
    }
  ]
}
